import React from 'react'
import styled from 'styled-components'


const MessageWrapper = styled.div `
margin:0 auto;
width:90%;
`

const MessageHeader = styled.div `
width:90%;
heidht:40px;
display:flex;
`
const BUYMessage = styled.div `
display:inline-block;
width:50%;
height:100%;
border:1px solid grey;
font-size:0.9rem;
color:grey;
text-align:center;
line-height:40px;
`

const SELLMessage = styled.div `
width:50%;
display:inline-block;
height:100%;
border:1px solid grey;
font-size:0.9rem;
color:grey;
text-align:center;
line-height:40px;
`

export default function MeMessages () {



	return (
		<MessageWrapper>
			<MessageHeader>
				<BUYMessage>BUY MESSAGES</BUYMessage>
				<SELLMessage>SELL MESSAGES</SELLMessage>
			</MessageHeader>
		</MessageWrapper>


	)
}
